import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Chapter 10: Search and Code Intelligence","description":"Implementing grep, glob, regex, and tree-sitter powered tools that give your agent the ability to understand and navigate codebases.","frontmatter":{"title":"Chapter 10: Search and Code Intelligence","description":"Implementing grep, glob, regex, and tree-sitter powered tools that give your agent the ability to understand and navigate codebases."},"headers":[],"relativePath":"learn/project/10-search-and-code-intelligence/index.md","filePath":"learn/project/10-search-and-code-intelligence/index.md"}'),n={name:"learn/project/10-search-and-code-intelligence/index.md"};function l(o,e,s,c,d,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="search-and-code-intelligence" tabindex="-1">Search and Code Intelligence <a class="header-anchor" href="#search-and-code-intelligence" aria-label="Permalink to &quot;Search and Code Intelligence&quot;">​</a></h1><p>A coding agent that cannot search and understand code is like a developer without an IDE. In previous chapters you built tools that read, write, and edit files -- but those tools require the agent to already know <em>which</em> file to open and <em>where</em> the relevant code lives. This chapter builds the search and code intelligence tools that transform your agent from a general-purpose assistant into a true coding partner. You will implement grep, glob, and regex-powered search tools, then go deeper with tree-sitter for AST-level code understanding.</p><p>Starting with the fundamentals, you will build a grep tool that searches file contents with regex support and a glob tool that finds files by name pattern. You will learn how to write correct and performant regular expressions in Rust, and how to match file patterns efficiently across large directory trees. These tools give your agent the ability to find relevant code quickly -- the same way a human developer uses <code>Ctrl+Shift+F</code> in their editor or <code>rg</code> from the terminal.</p><p>The second half of the chapter introduces tree-sitter, a powerful incremental parsing library that builds concrete syntax trees for source code. You will use tree-sitter to implement AST navigation, semantic search that understands code structure, and language-aware search that can find function definitions, type declarations, and call sites. By the end, your agent will have a suite of search tools that rival what a human developer gets from their editor.</p><h2 id="learning-objectives" tabindex="-1">Learning Objectives <a class="header-anchor" href="#learning-objectives" aria-label="Permalink to &quot;Learning Objectives&quot;">​</a></h2><ul><li>Build a grep tool with regex support, file filtering, and context line display</li><li>Implement a glob tool for fast file pattern matching across directory trees</li><li>Write correct and performant regular expressions using the <code>regex</code> crate</li><li>Combine gitignore rules, glob patterns, and binary detection into a unified file filter</li><li>Integrate tree-sitter for language-aware parsing and AST navigation</li><li>Implement semantic search that understands code structure beyond text matching</li><li>Detect programming languages and select the correct parser automatically</li><li>Rank and present search results effectively within context window constraints</li><li>Register all search tools with the agent&#39;s tool system using descriptive JSON schemas</li></ul><h2 id="subchapters" tabindex="-1">Subchapters <a class="header-anchor" href="#subchapters" aria-label="Permalink to &quot;Subchapters&quot;">​</a></h2><ol><li><a href="/project/10-search-and-code-intelligence/01-grep-tool.html">Grep Tool</a></li><li><a href="/project/10-search-and-code-intelligence/02-glob-tool.html">Glob Tool</a></li><li><a href="/project/10-search-and-code-intelligence/03-regex-in-rust.html">Regex In Rust</a></li><li><a href="/project/10-search-and-code-intelligence/04-file-pattern-matching.html">File Pattern Matching</a></li><li><a href="/project/10-search-and-code-intelligence/05-tree-sitter-intro.html">Tree Sitter Intro</a></li><li><a href="/project/10-search-and-code-intelligence/06-ast-navigation.html">AST Navigation</a></li><li><a href="/project/10-search-and-code-intelligence/07-semantic-search.html">Semantic Search</a></li><li><a href="/project/10-search-and-code-intelligence/08-code-aware-search.html">Code Aware Search</a></li><li><a href="/project/10-search-and-code-intelligence/09-language-detection.html">Language Detection</a></li><li><a href="/project/10-search-and-code-intelligence/10-search-result-ranking.html">Search Result Ranking</a></li><li><a href="/project/10-search-and-code-intelligence/11-integrating-search-tools.html">Integrating Search Tools</a></li><li><a href="/project/10-search-and-code-intelligence/12-summary.html">Summary</a></li></ol><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Chapter 4: Tool system architecture and the <code>Tool</code> trait</li><li>Chapter 5: File operation tools and path handling patterns</li><li>Chapter 9: Context management (understanding token budgets for result truncation)</li><li>Familiarity with regular expressions at a basic level (helpful but not required)</li></ul>',10)])])}const u=t(n,[["render",l]]);export{p as __pageData,u as default};
